import java.util.Scanner;

public class Calculator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("=== Java Calculator ===");
        System.out.println("Type 'help' for commands, 'quit' to exit.");

        while (true) {
            System.out.print("> ");
            if (!scanner.hasNextLine()) break;

            String input = scanner.nextLine().trim();
            if (input.isEmpty()) continue;

            switch (input.toLowerCase()) {
                case "quit":
                    System.out.println("Goodbye!");
                    return;
                case "help":
                    printHelp();
                    break;
                default:
                    try {
                        double result = evaluate(input);
                        System.out.println(formatResult(result));
                    } catch (Exception e) {
                        System.out.println("Error: " + e.getMessage());
                    }
            }
        }
    }

    private static void printHelp() {
        System.out.println("\n--- Help Menu ---");
        System.out.println("Supported operations: +, -, *, /");
        System.out.println("Format: <number> <operator> <number>");
        System.out.println("Examples: 10 + 5, 20 / 4, 3.5 * 2");
        System.out.println("-----------------\n");
    }

    private static double evaluate(String input) {
        String[] parts = input.split("\\s+");
        if (parts.length != 3) {
            throw new IllegalArgumentException("Invalid format. Use: <number> <operator> <number>");
        }

        try {
            double a = Double.parseDouble(parts[0]);
            double b = Double.parseDouble(parts[2]);
            String op = parts[1];

            switch (op) {
                case "+": return a + b;
                case "-": return a - b;
                case "*": return a * b;
                case "/":
                    if (b == 0.0) throw new ArithmeticException("Cannot divide by zero");
                    return a / b;
                default:
                    throw new IllegalArgumentException("Unknown operator: " + op);
            }
        } catch (NumberFormatException e) {
            throw new NumberFormatException("Invalid number format. Please enter valid numbers.");
        }
    }

    private static String formatResult(double result) {
        if (result == Math.floor(result) && !Double.isInfinite(result)) {
            return String.valueOf((long) result);
        }
        return String.valueOf(result);
    }
}

import java.util.Scanner;

/**
 * A command-line calculator application that supports basic arithmetic operations,
 * handles division by zero, and provides a user-friendly REPL interface.
 */
public class Calculator {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("--- Java Command-Line Calculator ---");
        System.out.println("Instructions: Enter a calculation (e.g., '10 + 5') or type 'help' for info.");
        System.out.println("Type 'quit' to exit the program.");

        while (true) {
            System.out.print("\n> ");
            String input = scanner.nextLine().trim();

            if (input.isEmpty()) {
                continue;
            }

            // Handle control commands
            if (input.equalsIgnoreCase("quit")) {
                System.out.println("Exiting calculator. Goodbye!");
                break;
            }

            if (input.equalsIgnoreCase("help")) {
                printHelp();
                continue;
            }

            // Process arithmetic expressions
            processExpression(input);
        }

        scanner.close();
    }

    /**
     * Prints the help menu to the console.
     */
    private static void printHelp() {
        System.out.println("Help Menu:");
        System.out.println("- Supported operations: +, -, *, /");
        System.out.println("- Format: [number] [operator] [number]");
        System.out.println("- Example: 10 + 5 or 20 * 4");
        System.out.println("- Note: You can include spaces (e.g., '10 + 5') or not (e.g., '10+5').");
        System.out.println("- Type 'quit' to exit.");
    }

    /**
     * Parses and evaluates the input string as a mathematical expression.
     * @param input The raw string from the user.
     */
    private static void processExpression(String input) {
        int opIndex = -1;
        char operator = ' ';

        // Identify the position of the operator (+, -, *, /)
        // We skip index 0 to allow for negative numbers (e.g., "-5+2")
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c == '+' || c == '-' || c == '*' || c == '/') {
                // If the operator is at index 0, it's likely a sign for a negative number
                if ((c == '+' || c == '-') && i == 0) continue;

                opIndex = i;
                operator = c;
                break;
            }
        }

        if (opIndex == -1) {
            System.out.println("Error: Invalid input. Please provide a valid expression like '10 + 5'.");
            return;
        }

        String leftPart = input.substring(0, opIndex).trim();
        String rightPart = input.substring(opIndex + 1).trim();

        if (leftPart.isEmpty() || rightPart.isEmpty()) {
            System.out.println("Error: Missing operand. Please provide both numbers.");
            return;
        }

        try {
            double num1 = Double.parseDouble(leftPart);
            double num2 = Double.parseDouble(rightPart);

            switch (operator) {
                case '+':
                    System.out.println(num1 + num2);
                    break;
                case '-':
                    System.out.println(num1 - num2;
                    break;
                case '*':
                    System.out.println(num1 * num2);
                    break;
                case '/':
                    if (num2 == 0) {
                        System.out.println("Error: Division by zero is not allowed.");
                    } else {
                        System.out.println(num1 / num2);
                    }
                    break;
                default:
                    System.out.println("Error: Unknown operator.");
            }
        } catch (NumberFormatException e) {
            System.out.println("Error: Invalid number format. Please use numeric values.");
        } catch (Exception e) {
            System.out.println("An unexpected error occurred: " + e.getMessage());
        }
    }
}

