                    System.out.println("Division by zero is not allowed.");
                }
            }
        }

        scanner.close();
    }

    private static double calculate(double num1, String operator, double num2) throws ArithmeticException {
        switch (operator) {
            case "+":
                return num1 + num2;
            case "-":
                return num1 - num2;
            case "*":
                return num1 * num2;
            case "/":
                if (num2 == 0) {
                    throw new ArithmeticException("Division by zero is not allowed.");
                }
                return num1 / num2;
            default:
                throw new IllegalArgumentException("Invalid operator.");
        }
    }

