        System.out.println("  /      - division");
    }

    private static void evaluate(String[] tokens) {
        if (tokens.length != 3) {
            System.out.println("Error: Invalid input format. Use \"help\" for usage.");
            return;
        }

        double a, b;
        try {
            a = Double.parseDouble(tokens[0]);
            b = Double.parseDouble(tokens[2]);
        } catch (NumberFormatException e) {
            System.out.println("Error: Both operands must be valid numbers.");
            return;
        }

        char op = tokens[1].charAt(0);
        double result;
        switch (op) {
            case '+':
                result = a + b;
                break;
            case '-':
                result = a - b;
                break;
            case '*':
                result = a * b;
                break;
            case '/':
                if (b == 0) {
                    System.out.println("Error: Division by zero is not allowed.");
                    return;
                }
                result = a / b;
                break;
            default:
                System.out.println("Error: Unsupported operator. Use +, -, *, or /.");
                return;
        }

        System.out.printf("%f%n", result);
    }
}

import java.util.Scanner;

public class Calculator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("=== Welcome to Java Calculator ===");
        System.out.println("Type 'help' for commands, 'quit' to exit");
        System.out.println();

        while (true) {
            System.out.print("> ");
            String input = scanner.nextLine().trim();

            if (input.equalsIgnoreCase("quit") || input.equalsIgnoreCase("exit")) {
                System.out.println("Goodbye!");
                break;
            } else if (input.equalsIgnoreCase("help")) {
                printHelp();
            } else if (input.isEmpty()) {
                continue;
            } else {
                try {
                    calculate(input);
                } catch (Exception e) {
                    System.out.println("Error: " + e.getMessage());
                }
            }
        }

        scanner.close();
    }

    private static void printHelp() {
        System.out.println("Available commands:");
        System.out.println("  help     - Show this help message");
        System.out.println("  quit/exit - Exit the calculator");
        System.out.println("  +        - Addition");
        System.out.println("  -        - Subtraction");
        System.out.println("  *        - Multiplication");
        System.out.println("  /        - Division");
        System.out.println("Example: 5 + 3, 10 * 2, 15 / 3");
    }

    private static void calculate(String expression) {
        String[] parts = expression.split("\\s+");

        if (parts.length != 3) {
            throw new IllegalArgumentException("Invalid format. Use: number operator number");
        }

        double num1 = parseNumber(parts[0]);
        String operator = parts[1];
        double num2 = parseNumber(parts[2]);

        double result;
        switch (operator) {
            case "+":
                result = num1 + num2;
                break;
            case "-":
                result = num1 - num2;
                break;
            case "*":
                result = num1 * num2;
                break;
            case "/":
                if (num2 == 0) {
                    throw new ArithmeticException("Division by zero");
                }
                result = num1 / num2;
                break;
            default:
                throw new IllegalArgumentException("Unknown operator: " + operator);
        }

        System.out.printf("%.2f %s %.2f = %.2f%n", num1, operator, num2, result);
    }

    private static double parseNumber(String str) {
        try {
            return Double.parseDouble(str);
        } catch (NumberFormatException e) {
            throw new IllegalArgumentException("Invalid number: " + str);
        }
    }
}
